 11→// Claims extends jwt.RegisteredClaims with application-specific fields.
 12→type Claims struct {
 13→	jwt.RegisteredClaims
 14→	Email        string         `json:"email,omitempty"`
 15→	Roles        []string       `json:"roles,omitempty"`
 16→	Role         string         `json:"role,omitempty"`          // Supabase: "authenticated", "anon", etc.
 17→	TeamID       string         `json:"team_id,omitempty"`
 18→	ClientType   string         `json:"client_type,omitempty"`   // web|cli|mobile|desktop
 19→	AppMetadata  map[string]any `json:"app_metadata,omitempty"`  // Supabase: provider info
 20→	UserMetadata map[string]any `json:"user_metadata,omitempty"` // Supabase: user profile data
 21→}
 22→
 23→// NormalizedRoles returns a deduplicated union of Roles and the singular Role field.
 24→func (c *Claims) NormalizedRoles() []string {
 25→	seen := make(map[string]struct{}, len(c.Roles)+1)
 26→	var result []string
 27→	for _, r := range c.Roles {
 28→		if _, ok := seen[r]; !ok {
 29→			seen[r] = struct{}{}
 30→			result = append(result, r)
 31→		}
 32→	}
 33→	if c.Role != "" {
 34→		if _, ok := seen[c.Role]; !ok {
 35→			result = append(result, c.Role)
 36→		}
 37→	}
 38→	return result
 39→}
 40→
 41→// Provider extracts the authentication provider from AppMetadata.
 42→// Returns an empty string if the provider is not set or is not a string.
 43→func (c *Claims) Provider() string {
 44→	if c.AppMetadata == nil {
 45→		return ""
 46→	}
 47→	p, _ := c.AppMetadata["provider"].(string)
 48→	return p
 49→}
